# Push the known-good app.py to the FormAI inference Space.
#
# WHERE TO RUN: a Google Colab cell (or any Python env) that is already logged in
# to Hugging Face as saksham0510 (e.g. after `notebook_login()`). No token needs
# to be typed into any chat.
#
# WHY BASE64: the app.py bytes are embedded below as base64 so a copy/paste can
# never re-introduce the stray indentation that caused the original
# `IndentationError: unexpected indent` on line 2.
#
# WHAT IT DOES:
#   1. decodes the exact app.py bytes to ./app.py
#   2. compiles it locally to catch any syntax error before uploading
#   3. uploads it to spaces/saksham0510/formai-inference, triggering a rebuild

import base64
import py_compile
from huggingface_hub import HfApi

APP_B64 = ""

with open("app.py", "wb") as f:
    f.write(base64.b64decode(APP_B64))

py_compile.compile("app.py", doraise=True)
print("local app.py compiles OK")

HfApi().upload_file(
    path_or_fileobj="app.py",
    path_in_repo="app.py",
    repo_id="saksham0510/formai-inference",
    repo_type="space",
    commit_message="Fix IndentationError; self-contained app with keep-alive",
)
print("uploaded — Space will rebuild now")
